package com.jc.backend.recommendation.application;
import static com.jc.backend.CanonicalTestData.*;import static org.assertj.core.api.Assertions.*;import com.jc.backend.*;import com.jc.backend.database.DatabaseRequestIdentity;import com.jc.backend.post.*;import com.jc.backend.recommendation.p2.*;import com.jc.backend.recommendation.persistence.RecommendationStorageTypes.RunMode;import com.jc.backend.region.*;import com.jc.backend.user.*;import com.jc.recommendation.p2.P2EvaluationContracts.*;import com.jc.recommendation.p2.*;import com.jc.recommendation.p2.P2ExperimentAssigner.Assignment;import java.time.Instant;import java.util.*;import org.junit.jupiter.api.*;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.dao.DataAccessException;import org.springframework.jdbc.core.JdbcTemplate;import org.springframework.test.context.TestPropertySource;
@CanonicalPostgresTest @Tag("p2-verification") @TestPropertySource(properties={"app.recommendation.mode=CANARY","app.recommendation.canary-allocation-basis-points=10000","app.recommendation.canary-cursor-secret=0123456789abcdef0123456789abcdef","app.recommendation.canary-release-id=p2-baseline-v1","app.recommendation.p1.release-id=p2-treatment-v1","app.recommendation.p2.experiment-id=recommendation-p1","app.recommendation.p2.experiment-version=experiment-v1","app.recommendation.p2.assignment-salt=assignment-salt-v1","app.recommendation.p2.assignment-build-id=p2-assignment-build-v1","app.recommendation.p2.evaluator-build-id=p2-evaluator-build-v1"})
class RecommendationP2EvaluationIntegrationTest {@Autowired UserRepository users;@Autowired RegionRepository regions;@Autowired JourneyPostRepository posts;@Autowired PlaceRepository places;@Autowired DatabaseRequestIdentity identity;@Autowired RecommendationOrchestrationService orchestration;@Autowired RecommendationP1RuntimeService p1;@Autowired RecommendationP2AssignmentStore assignments;@Autowired RecommendationP2ObservationSource source;@Autowired RecommendationP2EvaluationService evaluations;@Autowired JdbcTemplate jdbc;
@Test void assignmentExposureEvaluationAndDecisionAreBoundAndAppendOnly(){UserAccount author=users.save(new UserAccount("p2-author@example.com","hash","p2-author"));Region seoul=region(regions,"KR-SEOUL");posts.saveAndFlush(publishedPost(places,author,seoul,"p2 route","p2 content"));List<Subject> subjects=new ArrayList<>();for(int i=0;i<4;i++){UserAccount user=users.save(new UserAccount("p2-user-"+i+"@example.com","hash","p2-user-"+i));String session="p2-session-"+i;RecommendationOrchestrationService.RunResult run;try(DatabaseRequestIdentity.Scope ignored=identity.open(user.getId())){run=orchestration.runCanary(new RecommendationOrchestrationService.CanaryRunRequest(user.getId(),session));}Instant ref=jdbc.queryForObject("select reference_time from public.recommendation_run where run_id=?",(r,n)->r.getTimestamp(1).toInstant(),run.runId());subjects.add(new Subject(user.getId(),session,run.runId(),ref));}
P2ExperimentAssigner assigner=new P2ExperimentAssigner();for(int i=0;i<subjects.size();i++){Subject s=subjects.get(i);Assignment a=assigner.assign("recommendation-p1","experiment-v1","user:"+s.userId(),i<2?0:10000,"assignment-salt-v1");Assignment stored=assignments.store(a,s.userId(),s.referenceTime(),"p2-assignment-build-v1");String run=s.runId();if(stored.variant()==Variant.TREATMENT)run=p1.executeTreatment(s.runId(),s.userId(),s.sessionId(),RunMode.CANARY).treatmentRunId();assignments.storeExposure(stored,run,s.userId(),s.sessionId(),s.referenceTime());}
Instant from=subjects.stream().map(Subject::referenceTime).min(Instant::compareTo).orElseThrow().minusSeconds(1),to=subjects.stream().map(Subject::referenceTime).max(Instant::compareTo).orElseThrow().plusSeconds(10);List<Observation> obs=source.findObservations("recommendation-p1","experiment-v1",from,to);assertThat(obs).hasSize(4);assertThat(obs).filteredOn(o->o.variant()==Variant.BASELINE).hasSize(2);assertThat(obs).filteredOn(o->o.variant()==Variant.TREATMENT).hasSize(2);assertThat(obs).allMatch(Observation::exposed);
EvaluationResult result=evaluations.evaluateRuntime(new RecommendationP2EvaluationService.EvaluationRequest("p2-evaluation:integration","p2-dataset:integration","ranking-v3","p1-policy-bundle-v1:home_feed:empty",from,to,to.plusSeconds(1),ReleaseState.SHADOW,ReleaseState.CANARY,true,"system:p2-integration"));assertThat(result.finalDecision()).isEqualTo(FinalDecision.HOLD);assertThat(result.targetState()).isEqualTo(ReleaseState.HOLD);assertThat(jdbc.queryForObject("select count(*)::integer from public.recommendation_p2_gate_result where evaluation_run_id=?",Integer.class,result.evaluationRunId())).isEqualTo(5);assertThat(jdbc.queryForObject("select final_decision from public.recommendation_p2_release_decision where evaluation_run_id=?",String.class,result.evaluationRunId())).isEqualTo("hold");assertThatThrownBy(()->jdbc.update("update public.recommendation_p2_evaluation_run set final_decision='live' where evaluation_run_id=?",result.evaluationRunId())).isInstanceOf(DataAccessException.class);Assignment conflict=assigner.assign("recommendation-p1","experiment-v1","user:"+subjects.getFirst().userId(),10000,"different-salt-v1");assertThatThrownBy(()->assignments.store(conflict,subjects.getFirst().userId(),subjects.getFirst().referenceTime(),"p2-assignment-build-v1")).isInstanceOf(DataAccessException.class).hasRootCauseInstanceOf(IllegalStateException.class);}
private record Subject(long userId,String sessionId,String runId,Instant referenceTime){} }
